// 全局作用域：不在任何函数或块内
const appName = "sAgent";  // 全局变量
var version = "1.0";       // 全局变量（var自动挂到window）

function anyFunction() {
  console.log(appName);  // "sAgent" ✅
}

if (true) {
  console.log(version);  // "1.0" ✅
}

// var 在浏览器中会挂到 window 对象
var globalVar = "污染";
console.log(window.globalVar); // "污染"

// let/const 不会挂到 window
let safeGlobal = "安全";
console.log(window.safeGlobal); // undefined

function createUser(name) {
  const id = generateId();  // 函数作用域变量
  const role = "user";      // 函数作用域变量
  return { name, id, role };
}

const user = createUser("小明");
console.log(user.name);  // "小明" ✅
console.log(id);         // ❌ ReferenceError!
console.log(role);       // ❌ ReferenceError!

// if 块
if (true) {
  let a = 1;      // 只在 if 块内可见
  const b = 2;    // 只在 if 块内可见
  var c = 3;      // ⚠️ 泄漏到外面！
}
console.log(a);  // ❌ ReferenceError
console.log(b);  // ❌ ReferenceError
console.log(c);  // 3 ✅ var 泄漏了！

// for 块
for (let i = 0; i < 3; i++) {
  let temp = i * 2;  // 每次循环独立的 temp
}
console.log(i);    // ❌ ReferenceError
console.log(temp);  // ❌ ReferenceError

switch (action) {
  case 'update': {
    // 必须加 {} 才能用 let/const！
    const newValue = computeValue();
    applyUpdate(newValue);
    break;
  }
  case 'delete': {
    const newValue = "deleted"; // ✅ 不同块，同名不冲突
    applyDelete(newValue);
    break;
  }
}

const lang = "JavaScript";  // ① 全局

function outer() {
  const topic = "作用域链";  // ② outer 函数

  function inner() {
    const detail = "查找规则";  // ③ inner 函数
    // 查找 lang：③没找到 → ②没找到 → ①找到！
    console.log(lang);   // "JavaScript"
    // 查找 topic：③没找到 → ②找到！
    console.log(topic);   // "作用域链"
    // 查找 detail：③找到！
    console.log(detail);  // "查找规则"
  }
  inner();
}
outer();

const x = "global";

function foo() {
  console.log(x);  // "global" — 由编写位置决定
}

function bar() {
  const x = "bar";
  foo();  // foo 内的 x 仍然是 "global"!
}
bar();  // 输出 "global"，不是 "bar"

// ✅ 推荐写法
const API = "...";       // 不会变的值 → const
for (let i = 0; ...)   // 循环变量 → let
if (cond) { let x = 1; } // 块内临时变量 → let

// ❌ 禁止写法
var anything = "...";   // 永远不用 var！
// 避免过多全局变量
